<script setup lang="ts">import {onMounted,ref} from 'vue';import {ElMessage} from 'element-plus';import {api} from '@/api/client';const rows=ref<any[]>([]);async function load(){rows.value=(await api.duplicates()).data.data.items}async function merge(id:number,keep='a'){await api.merge(id,keep);ElMessage.success('合并完成');load()}async function ignore(id:number){await api.ignore(id);ElMessage.success('已忽略');load()}onMounted(load)</script>
<template><ElCard shadow="never"><ElTable :data="rows"><ElTableColumn prop="id" label="ID"/><ElTableColumn prop="activity_a_id" label="活动 A"/><ElTableColumn prop="activity_b_id" label="活动 B"/><ElTableColumn prop="similarity" label="相似度"><template #default="s"><ElProgress :percentage="Math.round(s.row.similarity*100)"/></template></ElTableColumn><ElTableColumn prop="matched_fields" label="匹配字段"/><ElTableColumn label="操作" width="260"><template #default="s"><ElButton size="small" type="primary" @click="merge(s.row.id,'a')">保留 A</ElButton><ElButton size="small" @click="merge(s.row.id,'b')">保留 B</ElButton><ElButton size="small" type="warning" @click="ignore(s.row.id)">不是重复</ElButton></template></ElTableColumn></ElTable><ElEmpty v-if="!rows.length" description="暂无去重候选"/></ElCard></template>
